const loader = document.getElementById('loader');
window.addEventListener('load', () => {
setTimeout(() => {
loader.classList.add('hidden');
}, 1800);
});
const fadeElements = document.querySelectorAll('.fade-in');
const observerOptions = {
threshold: 0.1,
rootMargin: '0px 0px -40px 0px'
};
const fadeObserver = new IntersectionObserver((entries) => {
entries.forEach((entry, index) => {
if (entry.isIntersecting) {
const siblings = entry.target.parentElement.querySelectorAll('.fade-in');
let delay = 0;
siblings.forEach((sibling, i) => {
if (sibling === entry.target) {
setTimeout(() => {
sibling.classList.add('visible');
}, delay);
}
});
const allVisible = Array.from(siblings).filter(s => s.classList.contains('visible'));
delay = allVisible.length * 80;
setTimeout(() => {
entry.target.classList.add('visible');
}, Math.min(delay, 300));
fadeObserver.unobserve(entry.target);
}
});
}, observerOptions);
fadeElements.forEach(el => fadeObserver.observe(el));
const statNumbers = document.querySelectorAll('.stat-number');
let countersAnimated = false;
function animateCounters() {
if (countersAnimated) return;
const statsSection = document.getElementById('stats');
if (!statsSection) return;
const rect = statsSection.getBoundingClientRect();
if (rect.top < window.innerHeight && rect.bottom > 0) {
countersAnimated = true;
statNumbers.forEach(num => {
const target = parseInt(num.getAttribute('data-target'));
const duration = 2000;
const startTime = performance.now();
function updateCounter(currentTime) {
const elapsed = currentTime - startTime;
const progress = Math.min(elapsed / duration, 1);
const eased = 1 - Math.pow(1 - progress, 3);
const current = Math.round(eased * target);
num.textContent = current;
if (progress < 1) {
requestAnimationFrame(updateCounter);
}
}
requestAnimationFrame(updateCounter);
});
}
}
window.addEventListener('scroll', animateCounters);
animateCounters();
const heroTitle = document.querySelector('.hero-title');
if (heroTitle) {
const roles = ['Android Developer', 'Kotlin Enthusiast', 'Compose Builder'];
let roleIndex = 0;
let charIndex = 0;
let isDeleting = false;
heroTitle.innerHTML = '<span class="typing-text"></span>';
const typingSpan = heroTitle.querySelector('.typing-text');
function typeEffect() {
const currentRole = roles[roleIndex];
if (isDeleting) {
typingSpan.textContent = currentRole.substring(0, charIndex - 1);
charIndex--;
} else {
typingSpan.textContent = currentRole.substring(0, charIndex + 1);
charIndex++;
}
let typeSpeed = isDeleting ? 50 : 100;
if (!isDeleting && charIndex === currentRole.length) {
typeSpeed = 2000;
isDeleting = true;
} else if (isDeleting && charIndex === 0) {
isDeleting = false;
roleIndex = (roleIndex + 1) % roles.length;
typeSpeed = 500;
}
setTimeout(typeEffect, typeSpeed);
}
setTimeout(typeEffect, 2000);
}
const heroImage = document.querySelector('.hero-image-wrapper');
if (heroImage) {
document.addEventListener('mousemove', (e) => {
const x = (e.clientX / window.innerWidth - 0.5) * 20;
const y = (e.clientY / window.innerHeight - 0.5) * 20;
heroImage.style.transform = `translate(${x}px, ${y}px)`;
});
}
const projectCards = document.querySelectorAll('.project-card');
projectCards.forEach(card => {
card.addEventListener('mousemove', (e) => {
const rect = card.getBoundingClientRect();
const x = e.clientX - rect.left;
const y = e.clientY - rect.top;
const centerX = rect.width / 2;
const centerY = rect.height / 2;
const rotateX = (y - centerY) / 20;
const rotateY = (centerX - x) / 20;
card.style.transform = `perspective(1000px) rotateX(${rotateX}deg) rotateY(${rotateY}deg) translateY(-4px)`;
});
card.addEventListener('mouseleave', () => {
card.style.transform = 'perspective(1000px) rotateX(0) rotateY(0) translateY(0)';
});
});
const magneticBtns = document.querySelectorAll('.btn');
magneticBtns.forEach(btn => {
btn.addEventListener('mousemove', (e) => {
const rect = btn.getBoundingClientRect();
const x = e.clientX - rect.left - rect.width / 2;
const y = e.clientY - rect.top - rect.height / 2;
btn.style.transform = `translate(${x * 0.15}px, ${y * 0.15}px)`;
});
btn.addEventListener('mouseleave', () => {
btn.style.transform = 'translate(0, 0)';
});
});
document.querySelectorAll('a[href^="#"]').forEach(anchor => {
anchor.addEventListener('click', function (e) {
e.preventDefault();
const target = document.querySelector(this.getAttribute('href'));
if (target) {
const offset = 80;
const targetPosition = target.getBoundingClientRect().top + window.pageYOffset - offset;
window.scrollTo({
top: targetPosition,
behavior: 'smooth'
});
}
});
});
const resumeModal = document.getElementById('resumeModal');
const resumeBtn = document.getElementById('resumeBtn');
const modalClose = document.getElementById('modalClose');
const modalOverlay = document.getElementById('modalOverlay');
const modalIframe = document.getElementById('modalIframe');
if (resumeBtn && resumeModal) {
resumeBtn.addEventListener('click', (e) => {
e.preventDefault();
modalOverlay.classList.add('active');
document.body.style.overflow = 'hidden';
if (modalIframe) {
modalIframe.src = 'moataz_mansour_resume.html';
}
});
function closeModal() {
modalOverlay.classList.remove('active');
document.body.style.overflow = '';
if (modalIframe) {
modalIframe.src = '';
}
}
if (modalClose) {
modalClose.addEventListener('click', closeModal);
}
if (modalOverlay) {
modalOverlay.addEventListener('click', (e) => {
if (e.target === modalOverlay) {
closeModal();
}
});
}
document.addEventListener('keydown', (e) => {
if (e.key === 'Escape' && modalOverlay.classList.contains('active')) {
closeModal();
}
});
}